	$(window).on("resize", function() {
		// not sure why, but increasing the minHeight seems to work, but not sure why
		TREE_CONST.minHeight = 12;
		resizeDiagram();
	});

	// TREE HEADER TOOLBAR
	// STRY0117600 - this event is raised when the switch to horizontal icon is clicked 
	$scope.$on("$tasker-tree-toolbar-icons.switchToHorizontal", function(){
		treeOrientation="Horizontal";
		treeNodeAngle=0;
		resetDiagram();
	});

	// TREE HEADER TOOLBAR
	// STRY0117600 - this event is raised when the switch to vertical icon is clicked 
	$scope.$on("$tasker-tree-toolbar-icons.switchToVertical", function(){
		treeOrientation="Vertical";
		treeNodeAngle=90;
		resetDiagram();
	});	

	function resetDiagram(){
		// STRY0125624 allow tree orientation to change
		// set default tree orientation based on system setting (this will change when user perference is enabled)
		if(treeOrientation == 'Horizontal'){
			treeNodeAngle = TREE_CONST.horizontalTreeAngle;
		} else {
			treeNodeAngle = TREE_CONST.verticalTreeAngle;
		}

		diagramInitCompleted = false;	
		drawTree();
		_setToolbarProperties();
		 // STRY0072032 - STRY0123997 no longer killing and rebuilding diagram, no need to destroy overviewdiv
		if (myOverview == undefined) {
			// STRY0116823
			myOverview =  $go(go.Overview, "myOverview",
												{ observed: diagram}); // , contentAlignment: go.Spot.Center
		}
		// DFCT0010275
		if($scope.data.map.length > 0){	
			// // STRY0072032 - this event handler is called when the diagram is first ready
			// LayoutCompleted fires whenever the layout changes
			diagram.addDiagramListener("InitialLayoutCompleted", function(e) {
				resizeDiagram();
				var node = diagram.findNodeForKey(c.data.selectedId);
				diagram.centerRect(node.actualBounds);
				// the diagram is initialized so the initial scale can be set
				// NOTE: zoomToFit and zoomToRect do not work in this init function
				// so calling a timeout function to initialize the scale
				$timeout(function(){ _initializeScale();},200);				
			});

			// TREE FOOTER TOOLBAR
			// STRY0117600 - this event handler is called when the diagram bounds change
			diagram.addDiagramListener("ViewportBoundsChanged", function(e) {
			// DFCT0011632 - on scrfoll or riesize tooltips were not being hidden - when the diagram bounds change, hide any open tooltips as they may have moved
				_hideAllPopovers();
				// set the footer scale when bounds change
				// but wait until init is completed
				if(viewPortHeight != diagram.viewportBounds.height){
					// this block only runs once per diagram load
					if(diagramInitCompleted){
						// only need to set scale after initial load
						// STRY0117945 STRY0125624 (cleared error when toolbar wasn't loaded)
						if(c.data.widgetTreeFooterToolbars){
							c.data.widgetTreeFooterToolbars[0].scale(diagram.scale);
						}
					}

					var node = diagram.findNodeForKey(c.data.selectedId);
					// and center it and select it
					// STRY0072032
					diagram.centerRect(node.actualBounds);
					viewPortHeight = diagram.viewportBounds.height;
				}
			});
		}
	}

	// ***************************************
	// this block only runs once
	// BEGIN BLOCK
	// ***************************************
	function _initializeScale(){
		if(c.data.widgetTreeFooterToolbars[0].data.isTree){
			// submit percent change back to server
			diagram.zoomToRect(diagram.documentBounds);
		} else {
			// get the initial scale from the footer widget
			diagram.scale = Number.parseFloat(c.data.widgetTreeFooterToolbars[0].data.settings.diagramScale);
		}
		diagramInitCompleted=true;
	}

	// ***************************************
	// END BLOCK
	// ***************************************

	// TREE FOOTER TOOLBAR
	// STRY0117600 - move toolbar into separate widget to use same functionality across all
	function _setToolbarProperties(){
		// STRY0117600 - pass a reference to diagram to toolbar
		// this sets the diagram on the toolbar so it can handle gojs events in the toolbar
		if(diagramInitCompleted){
			// this is needed to reset zoom to custom when the diagram changes
			c.data.widgetTreeFooterToolbars[0].resetDiagram(diagram);
		} else {
			c.data.widgetTreeFooterToolbars[0].diagram = diagram;
		}

		//c.data.widgetTreeFooterToolbar.diagram = diagram;
		// STRY0117600 - pass selectedId to toolbar
		// this sets the selected id on the footer tooltip when the selected id changes
		c.data.widgetTreeFooterToolbars[0].parentSelectedId = c.data.selectedId;
		c.data.widgetTreeFooterToolbars[0].currentTop = c.data.currentTopOU;

		// STRY0117600 - pass a reference to diagram to toolbar
		// this sets the diagram on the toolbar so it can handle gojs events in the toolbar
		c.data.widgetTreeHeaderToolbars[0].diagram = diagram;
		// STRY0117600 - pass selectedId to toolbar
		// this sets the selected id on the footer tooltip when the selected id changes
		c.data.widgetTreeHeaderToolbars[0].parentSelectedId = c.data.selectedId;
		c.data.widgetTreeHeaderToolbars[0].currentTop = c.data.currentTopOU;

	}

	function resizeDiagram() {
		// DFCT0010275
		if($scope.data.map && $scope.data.map.length > 0){	
			// Select the node using the sys_id parameter supplied.
			var node_select = diagram.findNodeForKey(c.data.selectedId);
			diagram.select(node_select);
		}
	}

	function drawTree() {
			// STRY0125255 - 
			if (diagram == undefined) {		diagram =
					$go(go.Diagram, TREE_CONST.node_id, {
					initialAutoScale: go.Diagram.Uniform,
					allowZoom: true,		
					// define the layout for the diagram
					layout: $go(go.TreeLayout, { angle:treeNodeAngle, nodeSpacing: TREE_CONST.spacingNode, layerSpacing: TREE_CONST.spacingLayer })
				});
			}	else {
				 // STRY0072032 - STRY0123997 no longer killing and rebuilding diagram, clear
				diagram.clear();
				diagram.layout.angle = treeNodeAngle;
			}
		diagram.model = new go.TreeModel($scope.data.map);
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		diagram.toolManager.hoverDelay = TREE_CONST.toolTipHoverDelay; // default is 850
		//diagram.toolManager.toolTipDuration = ; // default is 5000

		diagram.nodeTemplate = _createNodeTemplate();

		diagram.select(diagram.findNodeForKey(c.data.selectedId));
		diagram.allowVerticalScroll=true;
		// Define a trivial link template with no arrowhead
		diagram.linkTemplate = $go(go.Link, { selectable: false }, $go(go.Shape));  // the link shape
	}

	// **************************************************************************************************************
	// STRY0119818 - NOTE: reorganized Template and OU to put all of the repeated functions in the same block of code
	// TREE Code functions in all trees 
	// END BLOCK
	// **************************************************************************************************************	

	// **************************************************************************************************************	
	// DRAW TREE AND TREE LAYOUT FUCNTIONS
	// This block contains the functions that define the tree structure and capabilities
	// START BLOCK
	// **************************************************************************************************************	
	function _createNodeTemplate(){

		var nodeTemplate = $go(go.Node, treeOrientation,
													 { selectionAdorned: false,
														selectionChanged: nodeSelectionChanged,
														isTreeExpanded: true,
														isTreeLeaf: true
													 },  // this event handler is defined below

													 // on hover over node, show the icons
													 {mouseEnter: function(e, obj) {
														 obj.findObject('gradientRectangle').opacity =  c.data.settings.isFullScreen ? TREE_CONST.icon_opacity_normal : 0.0;
														 obj.findObject('Icons').visible=c.data.settings.isFullScreen;
													 },
														mouseLeave: function(e, obj) {
															obj.findObject('gradientRectangle').opacity = 0.0;
															obj.findObject('Icons').visible=false;
														}
													 },
													 _createTreeNode(),
													 $go("TreeExpanderButton") // this was overkill for small diagrams (shows the icon to expand/collapse)
													);
		return nodeTemplate;		
	}

	function _createTreeNode(){
		// STRY0111888 - changed to spot panel
		var treeNode =
				$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
						_createOurterRoundedRectangle(),
						// moved up b/c corner pictures were behind hover panel
						$go(go.Panel, "Auto", 
								createTMsAdminsNameAbbr(),
								hoverGradientPanel(),
								hoverIconPanel()
							 ), // close vertical panel for Task Manager, Administrator and Text
						createProfilePicCircle(),
						createProfilePicPhoto(),
						createPermissiveCircle(),
						createPermissiveIcon(),
						createOutstandingRequestCircle(),
						createOutstandingRequestIcon()
					 );
		return treeNode;
	}

	function _createOurterRoundedRectangle(){
		// STRY0113936, STRY0111888 - set width and height
		var roundedRectangle = 
				$go(go.Shape, "RoundedRectangle", { strokeWidth: TREE_CONST.outlineWidth, width: TREE_CONST.nodeOuterRectangelWidth, height:TREE_CONST.nodeOuterRectangelHeight},
						// if selected, outline the rectangle
						new go.Binding("stroke", "isSelected", function(s){
							if (s)
								return TREE_CONST.node_selected_border; 
							else
								return null;}).ofObject(""),
						// if we want to have same border width even on selected, remove this section
						new go.Binding("strokeWidth", "isSelected", function(s) {
							if (s)
								return TREE_CONST.node_selected_border_stroke_width;
							else
								return null;}).ofObject(""),
						new go.Binding("fill", "active", function (t){
							if(t)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}),
								// this does not appear to create a dashed border.  not sure if it is broken or if dash is not recognized
								new go.Binding("strokeDashArray", "isSelected", function(s) {
									if (s)
										return "dash";
									else
										return null;
								}).ofObject("")						
					 );
		return roundedRectangle;		
	}

	function createProfilePicCircle(){
		// STRY0111888 - added outer circle for border
		var profilePicCricle =
				$go(go.Shape, "Circle", 
						{visible: false,
						 // STRY0113936 
						 width: TREE_CONST.profilePicCircleSize, height: TREE_CONST.profilePicCircleSize, strokeWidth: TREE_CONST.outlineWidth, //fill: TREE_CONST.node_active_bg,
						 alignment: new go.Spot(0, 0, TREE_CONST.leftPicCornerOffset, TREE_CONST.topPicCornerOffset) 
						},
						new go.Binding("visible", "u_ou_primary_contact", function (u_ou_primary_contact){
							if(u_ou_primary_contact)
								return c.data.settings.isFullScreen && c.data.settings.include_poc_avatar;
							else
								return false;}),
						new go.Binding("fill", "active", function (t){
							if(t)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}),
						// if selected, outline the circle
						new go.Binding("stroke", "", function(node){
							if (node.isSelected)
								return TREE_CONST.node_selected_border; 
							else if(node.data.active)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}).ofObject("")
					 );
		return profilePicCricle;
	}

	function createProfilePicPhoto(){
		//STRY0111888 - changed alignment and works with Spot panel above
		var profilePicPhoto = 
				$go(go.Panel, "Spot", // panel to hold the image clipped into a circle
						{ isClipping: true,	alignment: new go.Spot(0, 0, TREE_CONST.leftPicCornerOffset, TREE_CONST.topPicCornerOffset),
							// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; start Profile photo
							toolTip: $go(go.HTMLInfo, 
							{
								show: showPopoverUserInfo,
								hide: hidePopoverUserInfo
							})
							// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; end Profile photo
						}, 
						new go.Binding("visible", "u_ou_primary_contact", function (u_ou_primary_contact){
							if(u_ou_primary_contact)
								return c.data.settings.isFullScreen && c.data.settings.include_poc_avatar;
							else
								return false;}),
						// STRY0113936
						$go(go.Shape, "Circle", { width: TREE_CONST.profilePicSize, strokeWidth: TREE_CONST.outlineWidth }),
							new go.Binding("fill", "active", function (t){
								if(t)
									return TREE_CONST.node_active_bg;
								else
									return TREE_CONST.node_inactive_bg;}),
						// this is a special picture just for the user
						$go(go.Picture, 
								{desiredSize: new go.Size(TREE_CONST.profilePicSize, TREE_CONST.profilePicSize),
								 imageStretch: go.GraphObject.UniformToFill
								}, 
								new go.Binding("source", "u_ou_primary_contact_photo"), 
								new go.Binding("name","u_ou_primary_contact_photoName"),
								new go.Binding("visible", "u_ou_primary_contact_photo", function (u_ou_primary_contact_photo){
									if(u_ou_primary_contact_photo)
										return true;
									else 
										return false;
								})
							 ), // end image picture object
						// added initials when photo doesn't exist.
						$go(go.TextBlock, {font: TREE_CONST.fontStyle, stroke: TREE_CONST.textStrokeColor },
								new go.Binding("text", "u_ou_primary_contact_profile", function(u_ou_primary_contact_profile){
											if(u_ou_primary_contact_profile){
												var strFirstName = u_ou_primary_contact_profile.first_name;
												var strLastName = u_ou_primary_contact_profile.last_name;
												var initials = strFirstName.substring(0, 1) + strLastName.substring(0, 1);
												return initials;
											} else
												return '';
										}),
								// only show initials if photo not found
								new go.Binding("visible", "u_ou_primary_contact_photo", function (u_ou_primary_contact_photo){
									if(u_ou_primary_contact_photo)
										return false;
									else 
										return true;
								})

							 )
					 ); // end panel holding circle and picture
		return profilePicPhoto;
	}

	// STRY0113880
	function createTMsAdminsNameAbbr(){
		// STRY0108231
		var tms_admins_name_abbr_panel = 
