								// DFCT0010761 =- added of 60
								{alignment: go.Spot.Left, height: TREE_CONST.tmAndAdminIconHeight},
								$go(go.Panel, "Horizontal", {alignment: go.Spot.Left,
																						 margin: new go.Margin(TREE_CONST.tmAndAdminTopMargin, 0, 0, 0)},  // Horizontal panel for Task Manager and Administrator
										addImage(c.data.icons.taskManager, 1.0, c.data.messages["Tasker - Title - TASK MANAGERS"], "tasking_authorities_list"),
										addImage(c.data.icons.Admin16, 1.0, c.data.messages["Tasker - Title - OU HIERARCHY ADMINISTRATORS"], "u_ou_hierarchy_administrators_list")
									 ),	// end horizonal panel for icons
								// DFCT0010761 =- changed the height to 35, marin to margin: new go.Margin(0, 5, 0, 5),									
								$go(go.Panel,  "Vertical", {alignment: go.Spot.Left, margin: TREE_CONST.nodeTextPanelMargin, 
																						minSize: new go.Size(TREE_CONST.textPanelMinWidth, TREE_CONST.textPanelMinHeight), 
																						maxSize: new go.Size(TREE_CONST.textPanelMaxWidth, TREE_CONST.textPanelMaxHeight) }, // Horizontal panel for Task Manager, Administrator and Text
										$go(go.TextBlock, {alignment: go.Spot.Left, textAlign:"left", font: TREE_CONST.fontStyle, stroke: TREE_CONST.textStrokeColor },
												new go.Binding("text", "office_name")),
										$go(go.TextBlock, {alignment: go.Spot.Left, textAlign:"left", font: TREE_CONST.fontStyleSmall, stroke: TREE_CONST.textStrokeColor, opacity: TREE_CONST.abbrOppacity},
