	}

	function hoverGradientPanel() {
		// ************************************************************************
		// NOTE: the block is FULL SCREEN ONLY
		// ************************************************************************
		var gradientPanel =		
				$go(go.Shape, "Rectangle",  // Horizontal panel for Image and Icons
						{opacity: 0.0,
						 name: "gradientRectangle",
						 strokeWidth: 0, 
						 alignment: go.Spot.Right,
						 angle: TREE_CONST.gradientAngle,
						 // DFCT0010761 =- changed width (which is hieght at 90 degress from 40 to 60
						 width: TREE_CONST.gradientHoverWidth, 
						 height: TREE_CONST.gradientHoverHeight, 
						 fill: $go(go.Brush, "Linear", TREE_CONST.gradientHoverActive)},
						// STRY0114110
						new go.Binding("fill", "active", function (t){
							if(t)
								return $go(go.Brush, "Linear", TREE_CONST.gradientHoverActive);
							else
								return $go(go.Brush, "Linear", TREE_CONST.gradientHoverInactive);})
					 );
		return gradientPanel;
	}

	function hoverIconPanel(){
		var hoverIcons = 
				$go(go.Panel, "Spot",  // Horizontal panel for Image and Icons
						{name: "Icons",
						 visible: false,
						 alignment: go.Spot.Right},
						$go(go.Panel, "Horizontal", // Horizontal panel that contains the icons, set to top right
								{visible: c.data.settings.isFullScreen,
								alignment: go.Spot.Right, width: TREE_CONST.gradientHoverIconPanelWidth, isOpposite: true},
								addImage(c.data.icons.GenericAddSub16, c.data.topIconOpacity, '', ''),
								addImage(c.data.icons.Request16, c.data.topIconOpacity, '', ''),
								// STRY0101474

