	function createPermissiveCircle() {
		// STRY0114088, STRY0111888 - if permissive show open lock (this graphic has an outter band.  so, don't need the border circle)
		var permissiveCircle =
				$go(go.Shape, "Circle", 
						{ width: TREE_CONST.iconCircleSize, strokeWidth: TREE_CONST.outlineWidth,
						 // STRY0113884
						 alignment: new go.Spot(0, 1, TREE_CONST.leftIconCornerOffset, TREE_CONST.bottomIconCornerOffset) },
						new go.Binding("visible", "u_ou_is_permissive", function (u_ou_is_permissive){
							if(u_ou_is_permissive)
								return c.data.settings.isFullScreen && c.data.settings.permissiveOn;
							else
								return false;}),
						new go.Binding("fill", "active", function (t){
							if(t)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}),
						// if selected, outline the circle
						new go.Binding("stroke", "", function(node){
							if (node.isSelected)
								return TREE_CONST.node_selected_border; 
							else if(node.data.active)
								return TREE_CONST.node_active_bg;
							else
								return TREE_CONST.node_inactive_bg;}).ofObject("")
					 );
		return permissiveCircle;				
	}

