	function addImage(img, opacity, toolTiptextHeader, toolTipBindingList) {
// NOTE: put go.picture in a function and pass what you need to clean this up

		// STRY0101474 - if the image wasn't laoded, don't add the image NOTE: we may wat to put placeholder here IF it is defined to keep the space
		if(img.src == undefined){
			img.src = '';
		}

		var imageJSON =
			$go(go.Picture, 
				{margin: new go.Margin(TREE_CONST.imageMarginTop, TREE_CONST.imageMarginRight, TREE_CONST.imageMarginBottom, TREE_CONST.imageMarginLeft),
				 alignment: go.Spot.TopRight,
				 source: img.src,
				 opacity: opacity}, 
					new go.Binding("opacity", toolTipBindingList, function(data){
							var lOpacity;
							if(toolTipBindingList == ''){
								// for now, leave always on
								lOpacity = opacity;
							} else {
								lOpacity = data != ''? TREE_CONST.icon_opacity_normal:0.0;
							}
							return lOpacity; // != ''? TREE_CONST.icon_opacity_normal:0.0;
						}),
					new go.Binding("source", '', function(data){
							var lSource;
							switch (img.src){
								case c.data.icons.ProcessRequestBadge24.src:
									lSource = data.isAdmin && data.u_outstanding_request_count > 0?img.src:'';
									break;
								// 2.8 | 2022-04-18 | mmcc | STRY0119470  - All Tasker users should have access to use organization requests icon
								//case c.data.icons.Request16.src:
								//	lSource = !data.isAdmin?img.src:'';
								//	break;
								case c.data.icons.GenericAddSub16.src:
								case c.data.icons.Divider:
									lSource = data.isAdmin?img.src:'';
									break;
								default:
									lSource = img.src;
									break;
							}
							return lSource;
						}),					
				{mouseEnter: function(e, obj) {
					 obj.saveOpacity = obj.opacity;
					if(obj.opacity != 0.0)  // only change if icon is showing
					 obj.opacity = TREE_CONST.icon_opacity_hover;
				 },
				 mouseLeave: function(e, obj) {
					 obj.opacity = obj.saveOpacity;
					 obj.saveOpacity = null;
				 },
				 click: function(e, obj) {
					 var objWidget = null;
					 switch (obj.source){
						 case c.data.icons.Information16.src:
						 case c.data.icons.taskManager.src:
						 case c.data.icons.Admin16.src:
							 objWidget = _buildFormWidgetObject(modalObjects.informationForm, 'Tasker - Organizational Unit Information', obj.part.data, false); 
							 openFormModal(objWidget); 
							 break;
						 case c.data.icons.SubOU16.src:
							 objWidget = _buildListWidgetObject(modalObjects.subOUList, 'Tasker - List of Sub OUs', obj.part.data);
							 openListModal(objWidget);
							 break;
						 case c.data.icons.OUMembers16.src:
							 objWidget = _buildListWidgetObject(modalObjects.membersOUList, 'Tasker - List of Members', obj.part.data);
							 openListModal(objWidget);
							 break;
						 case c.data.icons.Contacts16.src:
							 objWidget = _buildListWidgetObject(modalObjects.contactsOUList, 'Tasker - List of Contacts', obj.part.data);
							 openListModal(objWidget);
							 break;
						 case c.data.icons.Reports16.src:
							 objWidget = JSON.parse(JSON.stringify(modalObjects.OUReport));
							 objWidget.title = c.data.messages["Tasker - OU Reports for "] + ' - ' + obj.part.data.name;
							 objWidget.filter = objWidget.filter + obj.part.data.key; 
							 openReportModal(objWidget);
							 break;
						 // STRY0101474
						 case c.data.icons.ProcessRequestBadge24.src:
							 // 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
							 var url = '?id=discover_simple_processing_form&dcu_sys_id=&dcu_table=x_153465_discovert_tasker_requests' +
									'&dcu_ref=u_ou_parent&dcu_view=&query=u_ou_parent=' +
									obj.part.data.key +
									'^u_status=In progress&o=u_requested&d=desc';
							 window.open(url, '_blank');
							 break;
						 case c.data.icons.RelatedTasks16.src:
							 objWidget = _buildListWidgetObject(modalObjects.relatedTaskOUList, 'Tasker - Related Tasks', obj.part.data);
							 openListModal(objWidget);
							 break;
						 case c.data.icons.Request16.src:
							 objWidget = _buildFormWidgetObject(modalObjects.requestChangeForm, 'Tasker - Title - Request Hierarchy Update', obj.part.data, true);
							 objWidget.sys_id = -1;
							 objWidget.u_ou_parent = obj.part.data.key; 
							 openFormModal(objWidget); 
							 break;
						 case c.data.icons.GenericAddSub16.src:
							 objWidget = _buildFormWidgetObject(modalObjects.createNewForm, 'Tasker - Create New Sub OU', obj.part.data, true);
							 objWidget.sys_id = -1; 
							 objWidget.parent = obj.part.data.key; 
							 objWidget.query = 'parent=' + obj.part.data.key;
							 openFormModal(objWidget); 
							 break;

						 // STRY0101474 - used for divider
						 default:
							 break;
					 }
					 e.handled = true;
				 }		 
				},					
				new go.Binding("toolTip", "", function(e, obj){
				var toolTip = '';
//  2.8 | 2022-03-10 | mmcc | STRY0114672 Original if else
// 				if(toolTiptextHeader!='') {
// 					toolTip = toolTipDataListJSON(toolTiptextHeader, toolTipBindingList);
// 				} else if(img.title != '') {
// 					toolTip = toolTipSimple(img);
// 				}
				// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel; block the click; Popover List start	
				if (obj.source == c.data.icons.OUMembers16.src ||
					obj.source == c.data.icons.Contacts16.src || 
					obj.source == c.data.icons.ProcessRequestBadge24.src) {
					toolTip = $go(go.HTMLInfo, {
						show: _showPopoverList,
						hide: _hidePopoverList
					});
				// DFCT0011106 - if no managers or admins, don't show hover
				} else if (obj.source == c.data.icons.taskManager.src){
					if(obj.part.data.tasking_authorities_list.length > 0){
						toolTip = $go(go.HTMLInfo, {
							show: _showPopoverList,
							hide: _hidePopoverList
						});						
					}					
				} else if(obj.source == c.data.icons.Admin16.src){
					if(obj.part.data.u_ou_hierarchy_administrators_list.length > 0){
						toolTip = $go(go.HTMLInfo, {
							show: _showPopoverList,
							hide: _hidePopoverList
						});						
					}					

				} else if (obj.source == c.data.icons.LockOpenBadge24.src ||
					obj.source == c.data.icons.Information16.src ||
					obj.source == c.data.icons.SubOU16.src ||
					obj.source == c.data.icons.RelatedTasks16.src ||
					obj.source == c.data.icons.Request16.src ||
					obj.source == c.data.icons.GenericAddSub16.src) {
					toolTip = $go(go.HTMLInfo, {
						show: _showPopoverSimple,
						hide: _hidePopoverSimple
					});
				} else if(toolTiptextHeader!='') {
					toolTip = toolTipDataListJSON(toolTiptextHeader, toolTipBindingList);
				} else if(img.title != '') {
					toolTip = toolTipSimple(img);
				}
				// 2.8 | 2022-03-10 | mmcc | STRY0114672; List Popover end
				return toolTip;
			})
		);
		return imageJSON;
	}	
