	// -----------------------------------------------------------------------------------------------------------------
	// START TOOLTIPS
	// -----------------------------------------------------------------------------------------------------------------
	// STRY0108231
	function toolTipDataListJSON(textHeader, bindingList) {
		var toolTip;
		var underline = '_';

		var toolDataListJSON = 
				$go(go.Adornment, "Spot", "Auto",
						$go(go.Shape, "RoundedRectangle", {fill: TREE_CONST.toolTipBackgroundColor}),
						$go(go.Panel, {width:300},
								$go(go.Panel, "Vertical", {defaultAlignment: go.Spot.Left},
										$go(go.Panel, {defaultAlignment: go.Spot.Left},
												$go(go.TextBlock, 
														textHeader, 
														{textAlign:"left", margin:4, background: TREE_CONST.toolTipBackgroundColor}
													 ),
												$go(go.TextBlock, 
														underline.repeat(100), 
														{opacity: 0.5, stroke: TREE_CONST.toolTipHeaderTextColor, textAlign:"left", margin: 4, background: TREE_CONST.toolTipBackgroundColor}
													 )
											 ),
										$go(go.Panel, {defaultAlignment: go.Spot.Left},
												$go(go.Panel, "Table", new go.Binding("itemArray", bindingList),
														{ margin: 4,
														 defaultAlignment: go.Spot.Left,
														 itemTemplate:
														 $go(go.Panel, "TableRow",
																 {defaultAlignment: go.Spot.Left},
																 $go(go.TextBlock, new go.Binding("text", "displayName"),
																		 { column: 0, 
																			textAlign:"left",
																			background: TREE_CONST.toolTipBackgroundColor
																		 }
																		)
																)
														})
											 )
									 )
							 )
					 );
		return toolDataListJSON;
	}

		// STRY0108231
	function toolTipSimple(object) {
		var toolTip;
		var underline = '_';

		var toolDataListJSON = 
				$go(go.Adornment, "Spot", "Auto",
						$go(go.Shape, "RoundedRectangle", {fill: TREE_CONST.toolTipBackgroundColor}),
						$go(go.Panel, "Auto", //{width:300},
								$go(go.Panel, "Vertical", {defaultAlignment: go.Spot.Left},
										$go(go.Panel, {defaultAlignment: go.Spot.Left},
												$go(go.TextBlock, 
														object.title, 
														{textAlign:"left", margin:4, background: TREE_CONST.toolTipBackgroundColor}
													 )
											 )
									 )
							 )
					 );
		return toolDataListJSON;
	}

