	/* 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Pane */
	// Create an object to pass when a Form widget is opened
	function _buildFormWidgetObject(someOuList, title, objPartData, omitHeader) {
		var tempObjWidget = {};
		tempObjWidget = JSON.parse(JSON.stringify(someOuList));
		tempObjWidget.title = c.data.messages[title] + ': ' + objPartData.name;
		tempObjWidget.sys_id = objPartData.key;
		tempObjWidget.omitHeader = omitHeader;

		return tempObjWidget;
	}

	/* 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Pane */
	// Create an object to pass when a List widget is opened
	function _buildListWidgetObject(someOuList, title, objPartData) {
		var tempObjWidget = {};
		tempObjWidget = JSON.parse(JSON.stringify(someOuList));
		tempObjWidget.title = c.data.messages[title] + ': ' + objPartData.name;
		tempObjWidget.filter = tempObjWidget.filter + objPartData.key; 

		return tempObjWidget;
	}

	function _runPopoverList(obj, diagramLastInput) {
		var popoverAdjustLeft = 0;
		var popoverAdjustTop = 0;

		_resetPopoverListObject();
		c.data.isPopoverListOpened = true;
		c.data.popoverListOptions.isSpinnerShown = true;
		_setPopoverDisplayNone('popoverWrapper');
		_resetPopoverObject();

// 		since GoJS's use of HTMLInfo is outside of the AngularJS context, 
// 		we use below to have the bindings updated
		$scope.$apply();

		var objWidget = {};
		switch (obj.source) {
			case c.data.icons.OUMembers16.src:
				c.data.isOuMemberListNeeded = true;
				c.data.popoverListRecord.title = c.data.messages['Tasker - OU Members'];
				c.data.popoverListRecord.footerLink = c.data.messages['Tasker - Show More...'];
				// 2.8 | 2022-07-16 | raj  |  STRY0119734 - All Popovers- Empty State
				c.data.popoverListRecord.emptyState = c.data.messages['Tasker - No {0} available'].replace('{0}',c.data.popoverListRecord.title);
				c.data.popoverListOptions.modalType = 'listModal';
				c.data.popoverListOptions.isSimplePopover = false;
				c.data.popoverListOptions.maxRowsToDisplay = 5;
				popoverAdjustLeft = -115;
				popoverAdjustTop = 90;

				objWidget = _buildListWidgetObject(modalObjects.membersOUList, 'Tasker - List of Members', obj.part.data);
				break;
			case c.data.icons.Contacts16.src:
				c.data.isContactListNeeded = true;
				c.data.popoverListRecord.title = c.data.messages['Tasker - Contacts'];
				c.data.popoverListRecord.footerLink = c.data.messages['Tasker - Show More...'];
				// 2.8 | 2022-07-16 | raj  |  STRY0119734 - All Popovers- Empty State
				c.data.popoverListRecord.emptyState = c.data.messages['Tasker - No {0} available'].replace('{0}',c.data.popoverListRecord.title);
				c.data.popoverListOptions.modalType = 'listModal';
				c.data.popoverListOptions.isSimplePopover = false;
				c.data.popoverListOptions.maxRowsToDisplay = 5;
				popoverAdjustLeft = -115;
				popoverAdjustTop = 90;

				objWidget = _buildListWidgetObject(modalObjects.contactsOUList, 'Tasker - List of Contacts', obj.part.data);
				break;
			case c.data.icons.taskManager.src:
				c.data.isOuTaskManagerListNeeded = true;
				c.data.popoverListRecord.title = c.data.messages['Tasker - Title - TASK MANAGERS'];
				// c.data.popoverListRecord.footerLink = c.data.messages['Tasker - Show More...'];
				// 2.8 | 2022-07-16 | raj  |  STRY0119734 - All Popovers- Empty State
				c.data.popoverListRecord.emptyState = c.data.messages['Tasker - No {0} available'].replace('{0}',c.data.popoverListRecord.title);
				c.data.popoverListOptions.modalType = 'formModal';
				c.data.popoverListOptions.isSimplePopover = false;
				c.data.popoverListOptions.maxRowsToDisplay = undefined; // show all rows
				popoverAdjustLeft = -115;
				popoverAdjustTop = 90;

				objWidget = _buildFormWidgetObject(modalObjects.informationForm, 'Tasker - Organizational Unit Information', obj.part.data, false); 
				break;
			case c.data.icons.Admin16.src:
				c.data.isOuHierarchyAdminListNeeded = true;
				c.data.popoverListRecord.title = c.data.messages['Tasker - Title - OU HIERARCHY ADMINISTRATORS'];
				// c.data.popoverListRecord.footerLink = c.data.messages['Tasker - Show More...'];
				// 2.8 | 2022-07-16 | raj  |  STRY0119734 - All Popovers- Empty State
				c.data.popoverListRecord.emptyState = c.data.messages['Tasker - No {0} available'].replace('{0}',c.data.popoverListRecord.title);
				c.data.popoverListOptions.modalType = 'formModal';
				c.data.popoverListOptions.isSimplePopover = false;
				c.data.popoverListOptions.maxRowsToDisplay = undefined; // show all rows
				popoverAdjustLeft = -115;
				popoverAdjustTop = 90;

				objWidget = _buildFormWidgetObject(modalObjects.informationForm, 'Tasker - Organizational Unit Information', obj.part.data, false); 
				break;
			// STRY0101474
			case c.data.icons.ProcessRequestBadge24.src:
				// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
				var url = '?id=discover_simple_processing_form&dcu_sys_id=&dcu_table=x_153465_discovert_tasker_requests' +
				'&dcu_ref=u_ou_parent&dcu_view=&query=u_ou_parent=' +
				obj.part.data.key +
				'^u_status=In progress&o=u_requested&d=desc';
				c.data.popoverListOptions.isSimplePopover = true;
				c.data.popoverListOptions.isSpinnerShown = false;
				c.data.popoverListRecord.title = c.data.messages['Tasker - Pending Request'];
				c.data.popoverListRecord.footerLink = c.data.icons.ProcessRequestBadge24.alt;
				// 2.8 | 2022-07-16 | raj  |  STRY0119734 - All Popovers- Empty State
				c.data.popoverListRecord.emptyState = c.data.messages['Tasker - No {0} available'].replace('{0}',c.data.popoverListRecord.title);

				c.data.popoverListRecord.contactPageHref = url;
				popoverAdjustLeft = -80;
				popoverAdjustTop = 94;
				break;
			// STRY0101474 - used for divider
			default:
				break;
		}

		c.data.popoverListOptions.objWidget = objWidget;

		// position the arrow
		var pt = diagramLastInput.viewPoint;

		// Do not go left of the viewport edge
		if (pt.x + popoverAdjustLeft <= 0) {
			popoverAdjustLeft = 0;
		}

		// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
		var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];
		popoverDiv.style.display = "block";
		popoverDiv.style.left = Math.ceil(pt.x + popoverAdjustLeft) + 'px';
		popoverDiv.style.top = Math.ceil(pt.y + popoverAdjustTop) + 'px';

		_startPopoverListTimer();

		// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
		if (c.data.popoverListOptions.isSpinnerShown) {
			c.data.ouId = obj.part.data.sys_id;
			// TREE FOOTER TOOLBAR
			// STRY0117600 - does not like diagram posted back to server
			c.data.widgetTreeFooterToolbars[0].diagram = null;
			c.data.widgetTreeHeaderToolbars[0].diagram = null;

			// DFCT0011106 - clear the list before calling back to the server
			c.data.updatedOUList = [];
			c.data.popoverListRecord.persons = [];

			c.server.update().then(function() {

				// TREE FOOTER TOOLBAR
				// STRY0117600 - does not like diagram posted back to server
				// reset to diagram after it returns from server
				c.data.widgetTreeFooterToolbars[0].diagram = diagram;
				c.data.widgetTreeHeaderToolbars[0].diagram = diagram;

				c.data.popoverListRecord.persons = c.data.updatedOUList;
				c.data.popoverListOptions.isSpinnerShown = false;
			})['finally'](function() {
				$timeout(function() {
					$scope.$apply();
				});
			});
		} else {
			c.data.popoverListOptions.isSpinnerShown = false;
			$scope.$apply();
		}

	}

	/* 2.8 | 2022-03-28 | mmcc | STRY0108687 - DIA - Organizational Hierarchy Visual Indicators- Popover OUHA List- Additional Styling Changes */
	// Use this private function for a Popover that is not clickable
	function _runPopoverSimple(obj, diagramLastInput) {
		var popoverAdjustLeft = 0;
		var popoverAdjustTop = 0;

		_resetPopoverListObject();
		c.data.isPopoverListOpened = true;
		c.data.popoverListOptions.isSimplePopover = true;
		c.data.popoverListOptions.isSpinnerShown = true;
		_setPopoverDisplayNone('popoverWrapper');
		_resetPopoverObject();

// 		since GoJS's use of HTMLInfo is outside of the AngularJS context, 
// 		we use below to have the bindings updated
		$scope.$apply();

		switch (obj.source) {
			case c.data.icons.Information16.src:
				c.data.popoverListRecord.title = c.data.icons.Information16.title;
				popoverAdjustLeft = -140;
				popoverAdjustTop = 94;
				break;
			case c.data.icons.SubOU16.src:
				c.data.popoverListRecord.title = c.data.icons.SubOU16.title;
				popoverAdjustLeft = -140;
				popoverAdjustTop = 94;
				break;
// 			case c.data.icons.Reports16.src:
// 				objWidget = JSON.parse(JSON.stringify(modalObjects.OUReport));
// 				objWidget.title = c.data.messages["Tasker - OU Reports for "] + ' - ' + obj.part.data.name;
// 				objWidget.filter = objWidget.filter + obj.part.data.key; 
// 				openReportModal(objWidget);
// 				break;
			case c.data.icons.RelatedTasks16.src:
				c.data.popoverListRecord.title = c.data.icons.RelatedTasks16.title;
				popoverAdjustLeft = -80;
				popoverAdjustTop = 94;
				break;
			case c.data.icons.Request16.src:
				c.data.popoverListRecord.title = c.data.icons.Request16.title;
				popoverAdjustLeft = -135; // 130
				popoverAdjustTop = 94; 
				break;
			case c.data.icons.GenericAddSub16.src:
				c.data.popoverListRecord.title = c.data.icons.GenericAddSub16.title;
				popoverAdjustLeft = -70; // 110, 90
				popoverAdjustTop = 94; 
				break;
			case c.data.icons.LockOpenBadge24.src:
				c.data.popoverListRecord.title = c.data.icons.LockOpenBadge24.title;
				popoverAdjustLeft = -115; // 110
				popoverAdjustTop = 94;
				break;
			default:
				break;
		}

		// position the arrow
		var pt = diagramLastInput.viewPoint;

		// Do not go left of the viewport edge
		if (pt.x + popoverAdjustLeft <= 0) {
			popoverAdjustLeft = 0;
		}

		// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
		var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];
		popoverDiv.style.display = "block";
		popoverDiv.style.left = Math.ceil(pt.x + popoverAdjustLeft) + 'px';
		popoverDiv.style.top = Math.ceil(pt.y + popoverAdjustTop) + 'px';

		c.data.popoverListOptions.isSpinnerShown = false;
		$scope.$apply();
	}

	function _runPopoverUserInfo(objPartData, diagramLastInput) {
		_resetPopoverObject();
		c.data.isPopoverOpened = true;
		_setPopoverDisplayNone('popoverWrapperList');
		_resetPopoverListObject();

		c.data.popoverRecord = objPartData.u_ou_primary_contact_profile;
		c.data.popoverRecord.photo = _setStyleBackgroundImage(objPartData.u_ou_primary_contact_photo);

		// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		c.data.popoverRecord.messages = _loadProfileMessages(objPartData.office_abbreviation);
		c.data.popoverRecord.icons = _loadProfileIcons();

		// since GoJS's use of HTMLInfo is outside of the AngularJS context, 
		// we use below to have the bindings updated
		$scope.$apply();

		// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
		var popoverAdjustLeft = -190;
		var pt = diagramLastInput.viewPoint;
		var popoverDiv = angular.element(document.getElementById('popoverWrapper'))[0];
		popoverDiv.style.display = "block";

		// Do not go left of the viewport edge
		if (pt.x + popoverAdjustLeft <= 0) {
			popoverAdjustLeft = 0;
		}

		popoverDiv.style.left = Math.ceil(pt.x + popoverAdjustLeft) + "px";
		popoverDiv.style.top = Math.ceil(pt.y + 100) + "px";

		c.popoverTimeout = $timeout(function() {
			c.data.isPopoverOpened = false;
		}, diagram.toolManager.toolTipDuration - 100);
	}

	/* 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Pane */
	// Do not show the popover
	function _setPopoverDisplayNone(popover) {
		var popoverDiv = angular.element(document.getElementById(popover))[0];
		popoverDiv.style.display = "none";

		if (popover == 'popoverWrapperList') {
			$timeout.cancel(c.popoverListTimeout);
		} else {
			$timeout.cancel(c.popoverTimeout);
		}
	}

	// Returns a string to set a style tag over in the Macro HTML to display a persons' photo
	// Parameter photo is sys_user avatar field with .iix?t=small appended
	function  _setStyleBackgroundImage(photo) {
		var imageUrl = '';

		if (photo != undefined) {
			imageUrl = "background-image: url('" + photo + "');";
		} else {
			imageUrl = "background-image: url('Profile16.svg');";
		}

		return imageUrl;
	}

	function _startPopoverListTimer() {
		c.popoverListTimeout = $timeout(function() {
			c.data.isPopoverListOpened = false;
			c.data.popoverListOptions.isSpinnerShown = false;
		}, diagram.toolManager.toolTipDuration - 100);
	}
	// -----------------------------------------------------------------------------------------------------------------
	// END TOOLTIPS
	// -----------------------------------------------------------------------------------------------------------------

};

