(function($sp, input, data, options, gs) {
	// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel; declare once as global
	var taskWidgetData = new TaskWidgetData();
	// if messages not loaded, load messages
	var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-officehierarchy');

	//  STRY0113883 - reworked code flow
	main();

	function main() {
		// DFCT0010813
		data.table = 'x_153465_discovert_discover_office_hierarchy';

		// 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
		data.bifold = (input || {}).bifold || (options || {}).bifold || false;
		// 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
		convertToBool(['bifold']);

		if(input){
			_processInput();
		} else {
			_initialLoad();
		}
	}

	// ---------------------------------------------------------------------------
	// Begin of Functions
	// ---------------------------------------------------------------------------
	// STRY0117600 structuring code for maintainability 
	function _initialLoad(){
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; init as an empty object
		data.popoverRecord = {};

		// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
		data.popoverListRecord = {};
		data.popoverListOptions = {
			isSimplePopover: false,
			isSpinnerShown: false,
			maxRowsToDisplay: 5,
			modalType: 'listModal',
			objWidget: {}
		};

		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
		data.currentUser = gs.getUserID();

		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();

		// STRY0101474  - DFCT0010275
		data.isGHA = new	UserInfoScripts().UserHasRole('x_153465_discovert.tasker_organizational_admin');

		// DFCT0010813 - moved down to load messages and icons
		// if there is no top OU, then stop
		if (data.settings.topParentNeeded) {
			return;
		}

		var selectedId = _setSelected();

		_loadOUmap(selectedId, undefined);	
	}

	function _loadToolBars(){
		// TREE HEADER TOOLBAR
		// STRY0117600 - move toolbar into separate widget to use same functionality across all
		// STRY0120908 - added show separator
		var header_widget_parameters = {
			baseWidget: 'discovertasker-officehierarchy',
			// STRY0125624
			topId: data.currentTopOU,
			showSeparator: false,
			iconGroup: 'header'
		};
		data.widgetTreeHeaderToolbars = [];
		data.widgetTreeHeaderToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', header_widget_parameters)); 

		// TREE FOOTER TOOLBAR
		// STRY0117600 - move toolbar into separate widget to use same functionality across all
		var footer_widget_parameters = {
			baseWidget: 'discovertasker-officehierarchy',
			topId: data.currentTopOU,
			iconGroup: 'footer'
		};
		data.widgetTreeFooterToolbars = [];
		data.widgetTreeFooterToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', footer_widget_parameters));
	}

	// STRY0117600 structuring code for maintainability 
	function _processInput(){
		if(input.topOU){
			// STRY0125624
			data.topOU = input.topOU;
			_loadOUmap(input.topOU,input.topOU);
		} else if(input.isPhotoDataNeeded){
			//  STRY0113883
			data.isPhotoDataNeeded = false;
			data.updatedPhoto = _loadPhoto(input.getUserGUID, false);
		} else if(input.isProfileDataNeeded){
			//  STRY0113883
			data.isProfileDataNeeded = false;
			data.updatedPhoto = _loadPhoto(input.getUserGUID, false);
			data.updatedProfile = _loadProfile(input.getUserGUID);
		} else if(input.isOuMemberListNeeded) {
			// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
			data.isOuMemberListNeeded = false;
			data.updatedOUList = [];
			data.updatedOUList = taskWidgetData.getHoverMembersArray(input.ouId);
		} else if(input.isContactListNeeded) {
			// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
			data.isContactListNeeded = false;
			data.updatedOUList = [];
			data.updatedOUList = taskWidgetData.getHoverContactsArray(input.ouId);
		} else if(input.isOuTaskManagerListNeeded) {
			// STRY0115436 - STRY0108687
			data.isOuTaskManagerListNeeded = false;
			data.updatedOUList = [];
			data.updatedOUList = taskWidgetData.getOUTaskMManagersHoverArray(input.ouId);
		} else if(input.isOuHierarchyAdminListNeeded) {
			// STRY0115436 - STRY0108687				
			data.isOuHierarchyAdminListNeeded = false;
			data.updatedOUList = [];
			data.updatedOUList = taskWidgetData.getOUHierarchyAdministratorsHoverArray(input.ouId);
		} else if(input.changeTree){
			// STRY0121023 - STRY0121017
			_loadOUmap(input.selectedId, undefined);				
		}
	}

	//  STRY0113883
	function _loadProfile(userGUID) {
		return taskWidgetData.loadProfileInfo(userGUID);		
	}

	//  STRY0113883
	function _loadPhoto(userGUID, asBackgroundImage) {
		return taskWidgetData.loadPhotoInfo(userGUID, asBackgroundImage);
	}

	function _loadOUmap(selectedId, topOU){
		// DFCT0010813
		var map = data.map = [];
		data.selectedId = selectedId;

		var gr_ou = _getTopOUgr(selectedId, topOU);
		data.currentTopOU = gr_ou.getUniqueValue();
		if (!data.currentTopOU  || data.currentTopOU == '') {
			data.currentTopOU = null;
			return;
		}
		// DFCT0010838 needed to look for null string also
		if(!data.selectedId || 
			 data.selectedId == '' ||
			 data.selectedId == 'null' || 
			 data.selectedId == 'undefined'
			){
			data.selectedId = data.currentTopOU;
		}

		data.title = gr_ou.getValue('office_abbreviation');
		data.office_name = gr_ou.getValue('office_name');

		data.fieldsInModel = taskWidgetData.loadOfficeTreeFieldsAndFieldLabels(gr_ou);

		taskWidgetData.buildOUMap('discovertasker-officehierarchy', map, gr_ou, data.fieldsInModel);
		// moved here, any time reload map, reload toolbar
		_loadToolBars();
	}

	function _setSelected(){
		var sys_id;
		var selectedId;

		// DFCT0010838 needed to look for null string also
		sys_id = $sp.getParameter("sys_id");
		if(sys_id && sys_id !="null"){
			// set the default selected id from the url
			selectedId = sys_id;
		} else if(data.settings.favorite.value != ''){
			selectedId = data.settings.favorite.value;
		} else if (data.settings.defaultOU.value != ''){
			// do not override the URL or the favorite on load
			selectedId = data.settings.defaultOU.value;
		}
		return selectedId;

	}

	function _getTopOUgr (selectedId, topOU){
		var currentTopOU;
		if(topOU){
			currentTopOU = topOU;
		} else {
			var orgScripts = new OrganizationalScripts();
			currentTopOU = orgScripts.getTopOUId(selectedId);
		}
		// RJ -ET - Story 4
		var gr_TopOU = new GlideRecordSecure(data.table);
		if (!gr_TopOU.get(currentTopOU)) {

			// if the glide record isn't found, rather than returning no tree
			// find the first top OU and load the tree for it
			// DFCT0010838 reset glide record as the get call above corrupted it
			gr_TopOU = new GlideRecordSecure(data.table);
			gr_TopOU.addEncodedQuery("parentISEMPTY");
			gr_TopOU.query();
			gr_TopOU.next();	
		}
		return gr_TopOU;
	}

	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}	
})($sp, input, data, options, gs);
